solutions.javascript:
// Function to validate a Git tag name
function validateGitTagName(tagName) {
    if (tagName.startsWith('v')) {
        let version = tagName.substring(1);
        if (version.length > 100) {
            return false;
        }
        let parts = version.split('.');
        let maxLength = 0;
        for (let part of parts) {
            if (part.length > maxLength) {
                maxLength = part.length;
            }
        }
        return maxLength <= 100;
    }
    return false;
}

solutions.python:
class Solution:
    def validateGitTagName(self, tagName: str) -> bool:
        if tagName.startswith('v'):
            version = tagName.substring(1)
            parts = version.split('.');
            max_length = 0;
            for part in parts:
                if len(part) > max_length:
                    max_length = len(part)
            return max_length <= 100
        return False
